function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
  const validCoupons = code
    .map((c, i) => {
      const business = businessLine[i];
      const active = isActive[i];
      if (c === '' || !/^[a-zA-Z0-9_]+$/.test(c)) return null;
      if (!["electronics", "grocery", "pharmacy", "restaurant"].includes(business)) return null;
      if (!active) return null;
      return { code: c, businessLine: business };
